class _FakeObjectStorageTransport:
    """In-memory injected transport for the object-storage upload spine tests.

    Exercises the full spine (HEAD-before/PUT/HEAD-after/multipart) with no
    network and no new dependency.
    """

    def __init__(self, *, present=None, present_size=None, present_checksum=None, put_status="ok", truncate_multipart=False, put_status_sequence=None, part_status_sequence=None):
        self.store = {}
        self.creds_seen = []
        self.heads = []
        # Keys HEADed with presence_only=False, i.e. the ones that on real R2
        # would trigger a whole-object GetObject-and-rehash (V14). A presence+size
        # caller (verified adopt, presence_size skip fast-path) must never appear
        # here, so tests assert this list stays empty on the size-only paths.
        self.content_hash_heads = []
        self.put_calls = 0
        self.multipart_calls = 0
        self.part_calls = 0
        self.abort_calls = 0
        self.delete_calls = 0
        self.deleted_keys = []
        self._part_bytes = {}
        self._present = present  # None | "same" | "different"
        self._present_size = present_size
        self._present_checksum = present_checksum
        self._put_status = put_status
        # Optional per-call status sequence for retry tests; falls back to put_status.
        self._put_status_sequence = list(put_status_sequence) if put_status_sequence else None
        # Optional per-put_part status sequence: a non-"ok" value raises the real
        # provider error carrier so the executor's bounded retry loop sees the
        # true status_class for a MULTIPART failure (SA-3 multipart path).
        self._part_status_sequence = list(part_status_sequence) if part_status_sequence else None
        self._truncate_multipart = truncate_multipart

    def head_object(self, *, key, presence_only=False):
        self.heads.append(key)
        if not presence_only:
            # On real R2 this HEAD path GetObject-rehashes the whole body (V14).
            self.content_hash_heads.append(key)
        if key in self.store:
            v = self.store[key]
            sha = None if presence_only else v["sha"]
            return {"present": True, "size": v["size"], "checksum_sha256": sha}
        if self._present == "same" and self._present_size is not None:
            sha = None if presence_only else self._present_checksum
            return {"present": True, "size": self._present_size, "checksum_sha256": sha}
        if self._present == "different" and self._present_size is not None:
            sha = None if presence_only else "0" * 64
            return {"present": True, "size": self._present_size, "checksum_sha256": sha}
        return {"present": False, "size": None, "checksum_sha256": None}

    def put_object(self, *, key, data_path, size, content_sha256):
        self.put_calls += 1
        if self._put_status_sequence is not None:
            status = self._put_status_sequence.pop(0) if self._put_status_sequence else "ok"
        else:
            status = self._put_status
        if status != "ok":
            return {"status_class": status, "size": 0, "checksum_sha256": None, "etag_opaque": None}
        self.store[key] = {"size": size, "sha": content_sha256}
        return {"status_class": "ok", "size": size, "checksum_sha256": content_sha256, "etag_opaque": "etag-opaque"}

    def create_multipart(self, *, key):
        self.multipart_calls += 1
        return "upload-1"

    def put_part(self, *, key, upload_id, part_number, data):
        self.part_calls += 1
        if self._part_status_sequence is not None:
            status = self._part_status_sequence.pop(0) if self._part_status_sequence else "ok"
            if status != "ok":
                raise archive_services._ObjectStorageProviderError(status)
        self._part_bytes[key] = self._part_bytes.get(key, 0) + len(data)
        return {"etag_opaque": f"part-{part_number}", "part_number": part_number}

    def complete_multipart(self, *, key, upload_id, parts, content_sha256):
        if self._truncate_multipart:
            # Simulate a provider that cannot confirm a whole-object sha256.
            self.store[key] = {"size": 1, "sha": "0" * 64}
            return {"status_class": "ok"}
        # The after-HEAD compares against the real object size; record the true
        # accumulated byte count and content sha so HEAD-after passes.
        self.store[key] = {"size": self._part_bytes.get(key, 0), "sha": content_sha256}
        return {"status_class": "ok"}

    def abort_multipart(self, *, key, upload_id):
        self.abort_calls += 1

    def delete_object(self, *, key):
        self.delete_calls += 1
        self.deleted_keys.append(key)
        self.store.pop(key, None)


