    def test_runtime_context_returns_deterministic_redacted_json(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            archive_root = self.copy_fake_archive(Path(tmp) / "archive")

            args = ["runtime-context", str(archive_root), "--format", "json"]
            first_code, first_output = self.run_cli(args)
            second_code, second_output = self.run_cli(args)

            self.assertEqual(first_code, 0, first_output)
            self.assertEqual(second_code, 0, second_output)
            self.assertEqual(json.loads(first_output), json.loads(second_output))
            self.assertNotIn(str(archive_root), first_output)

            result = json.loads(first_output)
            self.assertTrue(result["ok"])
            self.assertEqual(result["lifecycle_action"], "runtime_context")
            self.assertEqual(result["archive_id"], "archive:personal:fake-life")
            self.assertEqual(result["archive_type"], "personal")
            self.assertEqual(result["scope"], "personal")
            self.assertEqual(
                result["paths"],
                {
                    "inbox": "inbox/",
                    "zettels": "zettels/",
                    "receipts": "receipts/",
                    "operational_context": "ops/operational-context.yml",
                    "object_manifest": "objects/manifests/files.jsonl",
                },
            )
            self.assertTrue(result["redaction"]["local_paths_redacted"])
            self.assertNotIn("local_archive_root", result)
            self.assertNotIn("local_paths", result)
            self.assertEqual(result["wom_kit_version"]["version"], archive_cli.__version__)
            self.assertEqual(result["wom_kit_version"]["version_label"], f"v{archive_cli.__version__}")
            self.assertEqual(result["wom_kit_version"]["source_of_truth"], "wom_kit.__version__")
            self.assertEqual(result["wom_kit_version"]["project_pin"]["status"], "missing")
            self.assertTrue(result["wom_kit_version"]["redaction"]["local_paths_redacted"])
            self.assertNotIn("local_paths", result["wom_kit_version"])
            operational_context = result["operational_context"]
            self.assertTrue(operational_context["ok"])
            self.assertEqual(operational_context["lifecycle_action"], "operational_context")
            self.assertEqual(operational_context["status"], "present")
            self.assertEqual(operational_context["record_path"], "ops/operational-context.yml")
            self.assertIn("session resets", operational_context["record"]["mission"]["summary"])
