            self.assertEqual(init_code, 0, init_output)
            before = self.snapshot_archive_files(archive_root)

            code, output = self.run_cli(
                [
                    "github-repo",
                    str(archive_root),
                    "--approve",
                    "--reviewed-by",
                    "person:me",
                    "--write-local-profile",
                    "--profile-id",
                    "profile:personal:username",
                    "--profile-slug",
                    "username",
                    "--github-owner",
                    "example-user",
                    "--github-account-ref",
                    "github:account:username",
                    "--format",
                    "json",
                ]
            )

            result = json.loads(output)
