                    "--provider",
                    "gmail",
                    "--provider",
                    "naver",
                    "--operation",
                    "header_metadata_scan",
                    "--selection-rule",
                    "newest_first",
                    "--reviewed-by",
                    "person:me",
                    "--approve",
                    "--format",
