            self.assertEqual(code, 0, output)
            self.assertTrue(result["ok"])
            self.assertTrue(result["dry_run"])
            self.assertEqual(result["lifecycle_action"], "credential_ref_plan")
            self.assertEqual(result["credential_store"], "keyring")
            self.assertEqual(result["credential_kind"], "openai_api_key")
            self.assertEqual(result["purpose"], "model_api_access")
            self.assertFalse(result["current_capability"]["os_keyring_read_implemented"])
            self.assertFalse(result["current_capability"]["secret_value_retrieval_implemented"])
            self.assertFalse(result["closed_actions"]["os_keyring_opened"])
            self.assertFalse(result["closed_actions"]["openai_api_called"])
            self.assertFalse(result["privacy_guards"]["secret_values_echoed"])
            self.assertEqual(result["would_change"], [])
